namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple, classic pizza with fresh mozzarella and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes over the dough.", "Tear mozzarella and distribute evenly.", "Bake for 10–12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 53
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta made with eggs, cheese, and guanciale.",
                Ingredients = ["Spaghetti", "Guanciale or pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = ["Cook spaghetti in salted water until al dente.", "Fry guanciale until crispy.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with guanciale.", "Remove from heat, stir in egg mixture quickly.", "Serve immediately with extra pecorino."],
                TotalRatings = 8, RatingSum = 38
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and spices, simmer 15 minutes.", "Stir in cream and cooked chicken.", "Simmer 10 minutes and serve with rice or naan."],
                TotalRatings = 15, RatingSum = 70
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Biryani", Category = "Indian",
                Description = "Fragrant layered rice with mixed vegetables and aromatic spices.",
                Ingredients = ["Basmati rice", "Mixed vegetables", "Onions", "Yogurt", "Biryani spice mix", "Saffron", "Ghee", "Mint leaves"],
                Steps = ["Soak rice for 30 minutes, then parboil.", "Fry onions until golden brown.", "Cook vegetables with spices and yogurt.", "Layer rice and vegetables in a heavy pot.", "Top with saffron milk, fried onions, and mint.", "Seal and cook on low heat for 25 minutes."],
                TotalRatings = 6, RatingSum = 27
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, and sour cream.", "Serve with salsa on the side."],
                TotalRatings = 10, RatingSum = 42
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh, creamy avocado dip with lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Red onion", "Cilantro", "Jalapeño", "Tomato", "Salt"],
                Steps = ["Halve avocados and remove pits.", "Mash avocado to desired consistency.", "Stir in diced onion, tomato, and jalapeño.", "Add chopped cilantro and lime juice.", "Season with salt to taste.", "Serve immediately with tortilla chips."],
                TotalRatings = 9, RatingSum = 41
            },
            new Recipe
            {
                Id = 7, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Description = "Classic chewy cookies loaded with chocolate chips.",
                Ingredients = ["Butter", "Sugar", "Brown sugar", "Eggs", "Vanilla extract", "All-purpose flour", "Baking soda", "Chocolate chips"],
                Steps = ["Preheat oven to 375°F.", "Cream butter and sugars until fluffy.", "Beat in eggs and vanilla.", "Mix in flour and baking soda.", "Fold in chocolate chips.", "Drop spoonfuls onto baking sheet and bake 9–11 minutes."],
                TotalRatings = 20, RatingSum = 94
            },
            new Recipe
            {
                Id = 8, Title = "Tiramisu", Category = "Desserts",
                Description = "Classic Italian layered dessert with coffee-soaked ladyfingers.",
                Ingredients = ["Ladyfingers", "Espresso", "Mascarpone", "Eggs", "Sugar", "Cocoa powder", "Marsala wine"],
                Steps = ["Brew espresso and let it cool, mix in Marsala.", "Separate eggs; whisk yolks with sugar until pale.", "Fold mascarpone into yolk mixture.", "Whip egg whites to stiff peaks, fold into mascarpone mixture.", "Dip ladyfingers in espresso and layer in dish.", "Alternate layers of cream and ladyfingers, dust with cocoa."],
                TotalRatings = 11, RatingSum = 50
            },
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title.Trim(),
            Category = category.Trim(),
            Description = $"A community-submitted {category.Trim().ToLowerInvariant()} recipe.",
            Ingredients = ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="star-btn @(star <= _selectedRating ? "filled" : "")"
                @onclick="() => Rate(star)"
                disabled="@_hasRated"
                title="Rate @star star@(star > 1 ? "s" : "")">
            @(star <= _selectedRating ? "★" : "☆")
        </button>
    }
    <span class="rating-info">
        @if (_hasRated)
        {
            <span class="text-success">Thanks for rating!</span>
        }
        @if (Recipe is not null && Recipe.TotalRatings > 0)
        {
            <span>@Recipe.AverageRating.ToString("0.0") avg (@Recipe.TotalRatings ratings)</span>
        }
    </span>
</div>

@code {
    [Parameter, EditorRequired]
    public Models.Recipe? Recipe { get; set; }

    [Inject]
    private RecipeService RecipeService { get; set; } = default!;

    private int _selectedRating;
    private bool _hasRated;

    private void Rate(int stars)
    {
        if (_hasRated || Recipe is null) return;
        _selectedRating = stars;
        _hasRated = true;
        RecipeService.AddRating(Recipe.Id, stars);
    }
}

.star-rating {
    display: flex;
    align-items: center;
    gap: 0.15rem;
    margin: 1rem 0;
}

.star-btn {
    background: none;
    border: none;
    font-size: 1.8rem;
    cursor: pointer;
    color: #ccc;
    padding: 0 0.1rem;
    transition: color 0.15s, transform 0.1s;
}

.star-btn:hover:not(:disabled) {
    transform: scale(1.2);
}

.star-btn.filled {
    color: #f5a623;
}

.star-btn:disabled {
    cursor: default;
}

.rating-info {
    margin-left: 0.75rem;
    font-size: 0.9rem;
    color: #666;
    display: flex;
    gap: 0.75rem;
}

@page "/category/{CategoryName}"
@using RecipeHub.Services

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">@recipe.Description</p>
                        <p class="card-text">
                            @if (recipe.TotalRatings > 0)
                            {
                                <small>★ @recipe.AverageRating.ToString("0.0") (@recipe.TotalRatings ratings)</small>
                            }
                            else
                            {
                                <small class="text-muted">No ratings yet</small>
                            }
                        </p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-link mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    [Inject]
    private RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<Models.Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Components.Shared
@using RecipeHub.Services

<PageTitle>@(_recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

@if (_recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
    <a href="/" class="btn btn-link">← Back to Home</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <h1>@_recipe.Title</h1>
    <p class="lead text-muted">@_recipe.Description</p>

    <StarRating Recipe="_recipe" />

    <div class="row mt-4">
        <div class="col-md-5">
            <h3>Ingredients</h3>
            <ul class="list-group list-group-flush">
                @foreach (var ingredient in _recipe.Ingredients)
                {
                    <li class="list-group-item">@ingredient</li>
                }
            </ul>
        </div>
        <div class="col-md-7">
            <h3>Steps</h3>
            <ol class="list-group list-group-numbered list-group-flush">
                @foreach (var step in _recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <a href="/category/@_recipe.Category" class="btn btn-link mt-4">← Back to @_recipe.Category Recipes</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    [Inject]
    private RecipeService RecipeService { get; set; } = default!;

    private Models.Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Services

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Your recipe "<strong>@_submittedTitle</strong>" has been added.</p>
        <a href="/recipe/@_submittedId" class="btn btn-primary me-2">View Recipe</a>
        <button class="btn btn-outline-secondary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">— Select a category —</option>
                @foreach (var cat in _categories)
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="_model.Ingredients"
                           placeholder="One ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="_model.Steps"
                           placeholder="One step per line&#10;e.g.,&#10;Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Combine with wet ingredients." />
            <ValidationMessage For="() => _model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject]
    private RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel _model = new();
    private IReadOnlyList<string> _categories = [];
    private bool _submitted;
    private string _submittedTitle = string.Empty;
    private int _submittedId;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        var recipe = RecipeService.AddRecipe(_model.Title, _model.Category, _model.Ingredients, _model.Steps);
        _submittedTitle = recipe.Title;
        _submittedId = recipe.Id;
        _submitted = true;
    }

    private void Reset()
    {
        _model = new();
        _submitted = false;
    }

    private sealed class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3–100 characters.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list at least one ingredient.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = string.Empty;
    }
}

