{"path": "/tmp/sv-6e1b29d8fdd9433797b0e4c854503bbe/RecipeHub/Components/Pages/SubmitRecipe.razor", "file_text": "@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Services

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Your recipe "<strong>@_submittedTitle</strong>" has been added.</p>
        <a href="/recipe/@_submittedId" class="btn btn-primary me-2">View Recipe</a>
        <button class="btn btn-outline-secondary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">— Select a category —</option>
                @foreach (var cat in _categories)
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="_model.Ingredients"
                           placeholder="One ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="_model.Steps"
                           placeholder="One step per line&#10;e.g.,&#10;Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Combine with wet ingredients." />
            <ValidationMessage For="() => _model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject]
    private RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel _model = new();
    private IReadOnlyList<string> _categories = [];
    private bool _submitted;
    private string _submittedTitle = string.Empty;
    private int _submittedId;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        var recipe = RecipeService.AddRecipe(_model.Title, _model.Category, _model.Ingredients, _model.Steps);
        _submittedTitle = recipe.Title;
        _submittedId = recipe.Id;
        _submitted = true;
    }

    private void Reset()
    {
        _model = new();
        _submitted = false;
    }

    private sealed class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3–100 characters.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list at least one ingredient.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = string.Empty;
    }
}
"}

