using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple, classic pizza with fresh mozzarella and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes over the dough.", "Tear mozzarella and distribute evenly.", "Bake for 10–12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 53
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta made with eggs, cheese, and guanciale.",
                Ingredients = ["Spaghetti", "Guanciale or pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = ["Cook spaghetti in salted water until al dente.", "Fry guanciale until crispy.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with guanciale.", "Remove from heat, stir in egg mixture quickly.", "Serve immediately with extra pecorino."],
                TotalRatings = 8, RatingSum = 38
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and spices, simmer 15 minutes.", "Stir in cream and cooked chicken.", "Simmer 10 minutes and serve with rice or naan."],
                TotalRatings = 15, RatingSum = 70
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Biryani", Category = "Indian",
                Description = "Fragrant layered rice with mixed vegetables and aromatic spices.",
                Ingredients = ["Basmati rice", "Mixed vegetables", "Onions", "Yogurt", "Biryani spice mix", "Saffron", "Ghee", "Mint leaves"],
                Steps = ["Soak rice for 30 minutes, then parboil.", "Fry onions until golden brown.", "Cook vegetables with spices and yogurt.", "Layer rice and vegetables in a heavy pot.", "Top with saffron milk, fried onions, and mint.", "Seal and cook on low heat for 25 minutes."],
                TotalRatings = 6, RatingSum = 27
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, and sour cream.", "Serve with salsa on the side."],
                TotalRatings = 10, RatingSum = 42
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh, creamy avocado dip with lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Red onion", "Cilantro", "Jalapeño", "Tomato", "Salt"],
                Steps = ["Halve avocados and remove pits.", "Mash avocado to desired consistency.", "Stir in diced onion, tomato, and jalapeño.", "Add chopped cilantro and lime juice.", "Season with salt to taste.", "Serve immediately with tortilla chips."],
                TotalRatings = 9, RatingSum = 41
            },
            new Recipe
            {
                Id = 7, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Description = "Classic chewy cookies loaded with chocolate chips.",
                Ingredients = ["Butter", "Sugar", "Brown sugar", "Eggs", "Vanilla extract", "All-purpose flour", "Baking soda", "Chocolate chips"],
                Steps = ["Preheat oven to 375°F.", "Cream butter and sugars until fluffy.", "Beat in eggs and vanilla.", "Mix in flour and baking soda.", "Fold in chocolate chips.", "Drop spoonfuls onto baking sheet and bake 9–11 minutes."],
                TotalRatings = 20, RatingSum = 94
            },
            new Recipe
            {
                Id = 8, Title = "Tiramisu", Category = "Desserts",
                Description = "Classic Italian layered dessert with coffee-soaked ladyfingers.",
                Ingredients = ["Ladyfingers", "Espresso", "Mascarpone", "Eggs", "Sugar", "Cocoa powder", "Marsala wine"],
                Steps = ["Brew espresso and let it cool, mix in Marsala.", "Separate eggs; whisk yolks with sugar until pale.", "Fold mascarpone into yolk mixture.", "Whip egg whites to stiff peaks, fold into mascarpone mixture.", "Dip ladyfingers in espresso and layer in dish.", "Alternate layers of cream and ladyfingers, dust with cocoa."],
                TotalRatings = 11, RatingSum = 50
            },
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title.Trim(),
            Category = category.Trim(),
            Description = $"A community-submitted {category.Trim().ToLowerInvariant()} recipe.",
            Ingredients = ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

