@using RecipeHub.Services

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="star-btn @(star <= _selectedRating ? "filled" : "")"
                @onclick="() => Rate(star)"
                disabled="@_hasRated"
                title="Rate @star star@(star > 1 ? "s" : "")">
            @(star <= _selectedRating ? "★" : "☆")
        </button>
