    <span class="rating-info">
        @if (_hasRated)
        {
            <span class="text-success">Thanks for rating!</span>
        }
        @if (Recipe is not null && Recipe.TotalRatings > 0)
        {
            <span>@Recipe.AverageRating.ToString("0.0") avg (@Recipe.TotalRatings ratings)</span>
        }
    </span>
</div>

@code {
    [Parameter, EditorRequired]
    public Models.Recipe? Recipe { get; set; }

    [Inject]
    private RecipeService RecipeService { get; set; } = default!;

    private int _selectedRating;
    private bool _hasRated;

    private void Rate(int stars)
    {
        if (_hasRated || Recipe is null) return;
        _selectedRating = stars;
        _hasRated = true;
        RecipeService.AddRating(Recipe.Id, stars);
    }
}

